var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"며칠 뒤","JPN":"数日後","ENG":"A few days later","TWN":"幾天後","SCN":"几天后","DEU":"A few days later","FRA":"A few days later"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>로터스</color>\\n아마니 밸리, 코핀 컴퍼니 임시 지부","JPN":"管理局直轄都市<color=#ffd34c>ロータス</color>\\nアマニーバレー、コフィンカンパニーの臨時支部","ENG":"[[","TWN":"管理局直轄城市<color=#ffd34c>洛德斯</color>\\n阿瑪尼山谷，科芬公司臨時支部","SCN":"管理局直辖城市<color=#ffd34c>洛德斯</color>\\n阿玛尼山谷，科芬公司临时支部","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자, 모두 모였으니 상황을 정리해 보죠.","JPN":"さて、これで全員集まったことですし、状況をまとめてみましょう。","ENG":"All right, now that everyone's here, let's go over the situation.","TWN":"好了，大家都到齊了，我們來整理一下情況吧。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우선, 이번 사태의 최우선 사항은 아시다시피 거대 우주선에 관한 정보입니다.","JPN":"まず今回の事態の最優先事項は、皆さんも知ってのとおり、巨大宇宙船に関する情報の入手です。","ENG":"As you know, our top priority is gathering information on the massive spaceship.","TWN":"首先，如你所知，這次事件的首要事項是關於巨型太空船的資訊。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지금으로부터 열흘 전.","JPN":"今から10日前。","ENG":"Ten days ago.","TWN":"從現在起十天前。"},"stage":{"bg":"MS_1407","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"샤레이드와 로터스의 관리 경계 구역에 거대한 우주선이 나타났죠.","JPN":"シャレードとロータスの管理警戒区域に、巨大宇宙船が現れました。","ENG":"A gigantic spaceship appeared in the Charade-Lotus perimeter zone.","TWN":"在查雷德和洛德斯的管理邊界區域出現了一艘巨大的太空船。"},"stage":{"bg":"MS_1407","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 우주선의 정체는 코핀 오브 릴리스. 통칭, 고철 더미의 모선이었습니다.","JPN":"この宇宙船の正体はコフィン・オブ・リリス。通称、鉄くずの母船でした。","ENG":"It has been identified as the Coffin of Lilith. It's commonly referred to as the mothership of Scraps.","TWN":"這艘太空船的真面目是科芬·莉莉絲，通稱，廢鐵堆的母艦。"},"stage":{"bg":"MS_1407","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"현재 모선은 어떠한 움직임도 보이지 않은 채, 그저 허공에 떠있을 뿐입니다만…….","JPN":"現在、母船は動きを見せず、ただ宙に浮いているだけですが……","ENG":"At present, the mothership remains suspended in the air, showing no signs of activity.","TWN":"目前母艦沒有任何動靜，只是漂浮在空中……"},"stage":{"bg":"MS_1407","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"고철 더미는 철저하게 정해진 기동 목적에 따라 움직이는 마왕.","JPN":"鉄くずは定められた起動目的に徹底的に従って動く魔王。","ENG":"However, Scraps is a Demon Lord that moves with precise intent and purpose.","TWN":"廢鐵堆是嚴格按照既定機動目的行動的魔王。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"따라서 녀석이 아무 행동도 취하지 않는 데에는 분명히 그만한 이유가 있을 겁니다.","JPN":"よって、やつが何の動きも見せないことには、相応の理由があるはずです。","ENG":"Which means her inaction is deliberate and likely meaningful.","TWN":"因此，那傢伙什麼都不做肯定是有原因的。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"저기, 부사장님?","JPN":"あの、副社長？","ENG":"Umm... Vice President?","TWN":"那個，副總？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"어쩌면 고철 더미의 목적은 거점의 방어가 아닐까?","JPN":"もしかしたら、鉄くずの目的は拠点の防御ではないかしら。","ENG":"What if the goal of Scraps is defense?","TWN":"或許廢鐵堆的目的是防禦據點？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"지난 정찰에서 우주선에 접근하니까, 갑자기 상당수의 모더레이터가 차원 도약해 왔거든.","JPN":"前回の偵察の時、宇宙船に接近したら結構な数のモデレーターが突然次元跳躍してきたの。","ENG":"During our last recon, when we got close to the spaceship, a large number of Moderators suddenly dimension-jumped in.","TWN":"在上次偵察中接近飛船時，突然有大量仲裁者用次元跳躍趕過來了。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"일리가 있군요. 하지만 현시점에서 단정하기에는 이릅니다.","JPN":"一理ある話ですね。ですが現時点ではまだ断言できません。","ENG":"That's a valid theory. However, it's still too early to draw any conclusions.","TWN":"說得有道理，但是現在下結論還為時過早。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어쩌면 고철 더미 또한 그곳에서 무언가를 찾고 있는 것일지도 모르니까요.","JPN":"もしかしたら鉄くずも、あそこで何かを探している可能性がありますからね。","ENG":"It's also possible that Scraps is looking for something in that area.","TWN":"也許那裡的廢鐵堆裡也在尋找著什麼東西。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어쨌든 분명한 건, 우주에 있던 마왕이 지상으로 내려올만한 원인이 있다는 거다.","JPN":"とにかくはっきりしていることは、宇宙にいた魔王が地上に降りたくなる何らかの原因があるということだ。","ENG":"What is clear is that a Demon Lord who had remained in space has now descended to Earth. And there must be a reason for that.","TWN":"不管怎樣，顯然宇宙中的魔王有理由降臨到地上。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그렇다면 우리의 최우선 목표는 그 원인을 파악 및 확보하는 것이겠지.","JPN":"とすれば、私たちの最優先目標はその原因の把握および確保となるだろう。","ENG":"Which means, our top priority is to identify and secure that reason.","TWN":"那麼我們的首要目標就是查明並掌握原因。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"좋습니다.","JPN":"いいでしょう。","ENG":"Understood.","TWN":"好的。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그럼, 두 번째 고려 사항은 스완의 행방입니다.","JPN":"次は、スワンの行方です。","ENG":"Now, on to our second concern. Swan's whereabouts","TWN":"那麼，第二個考慮事項是史旺的行蹤。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"시니어 리하르트를 살해하고, 관리국 최고등급 재난경보를 일으킨 주범.","JPN":"シニア・リヒャルトを殺害し、最高ランクの災難警報を引き起こした人物。","ENG":"She's the prime suspect in the murder of Senior Richard and the one who triggered the Administration's highest-level disaster alert.","TWN":"殺害高級官員裡理查，並引發管理局最高級別災難警報的罪魁禍首。"},"stage":{"bg":"MS_1201","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스완 클레어의 마지막 행선지가 샤레이드였죠.","JPN":"スワン・クレアの最後の行き先はシャレードでしたね。","ENG":"Her last known location was Charade.","TWN":"史旺·克萊爾的最後目的地是查雷德。"},"stage":{"bg":"MS_1201","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그녀가 행방을 감춘 시점과 고철 더미가 모습을 드러낸 시점은 거의 일치합니다.","JPN":"彼女が行方をくらました時点と、鉄くずが現れた時点はほぼ一致しています。","ENG":"The timing of her disappearance aligns almost exactly with the appearance of Scraps.","TWN":"她失蹤的時間點和廢鐵堆出現的時間點幾乎一致。"},"stage":{"bg":"MS_1201","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"따라서 정황상, 스완의 목적 또한 고철 더미의 등장과 관련이 있을 가능성이 매우 높죠.","JPN":"この状況からみて、スワンの目的は鉄くずの登場と何らかの関係がある可能性が高いでしょう。","ENG":"Which strongly suggests that Swan's objective may be connected to the emergence of Scraps.","TWN":"因此，從情境來看，史旺的目的也很可能與廢鐵堆的出現有關。"},"stage":{"bg":"MS_1201","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 마지막 고려 사항은 노엘 라이트 양의 존재입니다.","JPN":"最後はノエル・ライトさんの存在です。","ENG":"And the final matter to address is the existence of Noelle Wright.","TWN":"最後一個需要考慮的因素是洛艾兒·萊特的存在。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};